namespace ProductsApi.Models;

public enum Category
{
    Electronics,
    Clothing,
    Food,
    Books
}

namespace ProductsApi.Models;

public class Product
{
    public Guid Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public decimal Price { get; set; }
    public Category Category { get; set; }
    public DateTime CreatedAt { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace ProductsApi.Models;

public class CreateProductRequest
{
    [Required]
    [StringLength(200, MinimumLength = 1)]
    public string Name { get; set; } = string.Empty;

    [Range(0.01, double.MaxValue, ErrorMessage = "Price must be greater than zero.")]
    public decimal Price { get; set; }

    [Required]
    [EnumDataType(typeof(Category))]
    public Category Category { get; set; }
}

using ProductsApi.Models;

namespace ProductsApi.Services;

public interface IProductService
{
    IReadOnlyList<Product> GetAll();
    Product? GetById(Guid id);
    Product Create(CreateProductRequest request);
}

using System.Collections.Concurrent;
using ProductsApi.Models;

namespace ProductsApi.Services;

public class InMemoryProductService : IProductService
{
    private readonly ConcurrentDictionary<Guid, Product> _products = new();

    public IReadOnlyList<Product> GetAll()
    {
        return _products.Values.OrderByDescending(p => p.CreatedAt).ToList();
    }

    public Product? GetById(Guid id)
    {
        _products.TryGetValue(id, out var product);
        return product;
    }

    public Product Create(CreateProductRequest request)
    {
        var product = new Product
        {
            Id = Guid.NewGuid(),
            Name = request.Name,
            Price = request.Price,
            Category = request.Category,
            CreatedAt = DateTime.UtcNow
        };

        _products[product.Id] = product;
        return product;
    }
}

using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using ProductsApi.Models;
using ProductsApi.Services;

namespace ProductsApi.Controllers;

[ApiController]
[Route("api/[controller]")]
[Produces("application/json")]
public class ProductsController : ControllerBase
{
    private readonly IProductService _productService;

    public ProductsController(IProductService productService)
    {
        _productService = productService;
    }

    /// <summary>
    /// Retrieves all products.
    /// </summary>
    /// <returns>A list of all products ordered by creation date descending.</returns>
    /// <response code="200">Returns the list of products.</response>
    [HttpGet]
    [ProducesResponseType(typeof(IReadOnlyList<Product>), StatusCodes.Status200OK)]
    [EndpointSummary("List all products")]
    [EndpointDescription("Retrieves every product in the catalog, ordered by most recently created first.")]
    public ActionResult<IReadOnlyList<Product>> GetAll()
    {
        return Ok(_productService.GetAll());
    }

    /// <summary>
    /// Retrieves a single product by its unique identifier.
    /// </summary>
    /// <param name="id">The unique identifier of the product.</param>
    /// <returns>The requested product.</returns>
    /// <response code="200">Returns the requested product.</response>
    /// <response code="404">Product with the given ID was not found.</response>
    [HttpGet("{id:guid}")]
    [ProducesResponseType(typeof(Product), StatusCodes.Status200OK)]
    [ProducesResponseType(StatusCodes.Status404NotFound)]
    [EndpointSummary("Get a product by ID")]
    [EndpointDescription("Retrieves a single product by its globally unique identifier. Returns 404 if not found.")]
    public ActionResult<Product> GetById(Guid id)
    {
        var product = _productService.GetById(id);
        if (product is null)
        {
            return NotFound();
        }

        return Ok(product);
    }

    /// <summary>
    /// Creates a new product.
    /// </summary>
    /// <param name="request">The product data to create.</param>
    /// <returns>The newly created product.</returns>
    /// <response code="201">Product was created successfully.</response>
    /// <response code="400">Validation failed for the request body.</response>
    [HttpPost]
    [ProducesResponseType(typeof(Product), StatusCodes.Status201Created)]
    [ProducesResponseType(StatusCodes.Status400BadRequest)]
    [EndpointSummary("Create a new product")]
    [EndpointDescription("Creates a new product in the catalog. The server assigns an ID and timestamps the creation.")]
    public ActionResult<Product> Create([FromBody] CreateProductRequest request)
    {
        var product = _productService.Create(request);
        return CreatedAtAction(nameof(GetById), new { id = product.Id }, product);
    }
}

